qry:select.qry:xquery:
			for $r in sql('
	SELECT 
		PER02_PERSONAL_EMP.oi_personal_emp 
	FROM 
		PER02_PERSONAL_EMP 
		{%? (string(#SOURCE:@value)!='0') 
				{%, ORG02_ESTRUC_PERS %} 
				{% %} 
		%}
	WHERE
	1=1
	AND PER02_PERSONAL_EMP.oi_empresa = {%=string(#PARAM_GLOBALES:@oi_empresa)%}
	{%?(string(#SOURCE:@value)!='0') 
			{% AND PER02_PERSONAL_EMP.oi_personal_emp = ORG02_ESTRUC_PERS.oi_personal_emp
					AND ORG02_ESTRUC_PERS.oi_estructura IN ({%=string(#SOURCE:@value)%}) %} 
			{% %} 
	%}
	GROUP BY PER02_PERSONAL_EMP.oi_personal_emp 
')/ROWS/ROW

form:Form.form:Scripts:
		function Guardar()
{ 
 	Ctrl('legajos').DelAllRow();
 	for (key in arrA) Ctrl('legajos').AddRow().SetAttr('id', key.substr(1));

	Ctrl("main").DoEvent("SAVE");
}                   

//Ejecuta el Query Seleccionado y devuelve un ARRAY con el resultado
function exec_qry()
{
	var np, nSQL, i;

	np = new NomadProxy("", ut);
	nSQL = np.SQLService();

	var qry = Ctrl("main").getResource("qry_" + Ctrl("tab_filtro").GetSelectedPanelID());

	var qryMembers = qry.split("##");
	for (i=1; i<qryMembers.length; i+=2)
	{
		if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
		{
			alert("El valor es requerido");
			Ctrl(qryMembers[i]).SetFocus();
			return null;
		}				

		qryMembers[i]=EncodeXML(Ctrl(qryMembers[i]).GetXValue());
	}

  qry = qryMembers.join("");
  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(qry);

  var result = nSQL.Get(qry, "");
 	var resultArray = string2array(result);
 	// Ejecuta query EXTERNO
 	if (Ctrl("main").getResource("qry_externo"))
 	{
 		qry = Ctrl("main").getResource("qry_externo");
 		qryMembers = qry.split("##");
		for (i=1; i<qryMembers.length; i+=2)
		{
			qryMembers[i]=EncodeXML(Ctrl(qryMembers[i]).GetXValue());
		}
	  qry = qryMembers.join("");
	  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(Ctrl("DEBUG").GetXValue() + "\n\nQuery Externo:\n" + qry);
	  result = nSQL.Get(qry, "<PARAM oi_dictado=\""+Ctrl("oi_dictado").GetXValue()+"\" oi_empresa=\""+Ctrl("empresa").GetXValue()+"\"  />");
	  var auxResult = string2array(result);
	  intersect(resultArray, auxResult);
	}
	// Ejecuta query de ATRIBUTOS EXTERNOS
 	if (Ctrl("main").getResource("qry_externo_attr"))
 	{
 		qry = Ctrl("main").getResource("qry_externo_attr");
 		qryMembers = qry.split("##");
		for (i=1; i<qryMembers.length; i+=2)
		{
			qryMembers[i]=EncodeXML(Ctrl(qryMembers[i]).GetXValue());
		}
	  qry = qryMembers.join("");
	  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(Ctrl("DEBUG").GetXValue() + "\n\nQuery de Atributos Externos:\n" + qry);
	  result = nSQL.Get(qry, array2string(resultArray));
	  resultArray = string2array(result);
	}

  return resultArray;
}
